    isNumberPrime(valueToCheck, factorArray) {
        return valueToCheck >= 2 && factorArray[valueToCheck] === valueToCheck;
    }

    minJumps(numberSequence) {
        const sequenceLength = numberSequence.length;

        if (sequenceLength === 1) {
            return 0;
        }

        const smallestPrimeFactors = Solution.getSmallestPrimeFactors();

        let maximumValueInSequence = 0;
        let scanIndex = 0;
        while(scanIndex < sequenceLength){
            if(numberSequence[scanIndex] > maximumValueInSequence){
                maximumValueInSequence = numberSequence[scanIndex];
            }
            scanIndex++;
        }

        const primeNumbersEncountered = new Array(maximumValueInSequence + 1).fill(false);

        let numScanIndex = 0;
        while(numScanIndex < sequenceLength){
            const currentNumber = numberSequence[numScanIndex];
            if (this.isNumberPrime(currentNumber, smallestPrimeFactors)) {
                primeNumbersEncountered[currentNumber] = true;
            }
            numScanIndex++;
        }

        const primeFactorToIndicesMap = new Map();

        let sequenceElementIndex = 0;
        while (sequenceElementIndex < sequenceLength) {
            let currentNumberVal = numberSequence[sequenceElementIndex];

            if (currentNumberVal === 1) {
                sequenceElementIndex++;
                continue;
            }

            while (currentNumberVal > 1) {
                const currentPrimeFactor = smallestPrimeFactors[currentNumberVal];

                if (currentPrimeFactor <= maximumValueInSequence && primeNumbersEncountered[currentPrimeFactor]) {
                    if (!primeFactorToIndicesMap.has(currentPrimeFactor)) {
                        primeFactorToIndicesMap.set(currentPrimeFactor, []);
                    }
                    primeFactorToIndicesMap.get(currentPrimeFactor).push(sequenceElementIndex);
                }

                while (currentNumberVal % currentPrimeFactor === 0) {
                    currentNumberVal /= currentPrimeFactor;
                }
            }
            sequenceElementIndex++;
        }

        const distanceToPosition = new Array(sequenceLength).fill(-1);
        const teleportationPrimesUsed = new Array(maximumValueInSequence + 1).fill(false);

        const bfsTraversalQueue = [];

        bfsTraversalQueue.push(0);
        distanceToPosition[0] = 0;

        while (bfsTraversalQueue.length > 0) {
            const currentQueueIndex = bfsTraversalQueue.shift();

            if (currentQueueIndex === sequenceLength - 1) {
                return distanceToPosition[currentQueueIndex];
            }

            if (currentQueueIndex - 1 >= 0 && distanceToPosition[currentQueueIndex - 1] === -1) {
                distanceToPosition[currentQueueIndex - 1] = distanceToPosition[currentQueueIndex] + 1;
                bfsTraversalQueue.push(currentQueueIndex - 1);
            }

            if (currentQueueIndex + 1 < sequenceLength && distanceToPosition[currentQueueIndex + 1] === -1) {
                distanceToPosition[currentQueueIndex + 1] = distanceToPosition[currentQueueIndex] + 1;
                bfsTraversalQueue.push(currentQueueIndex + 1);
            }

            const valueAtCurrentPos = numberSequence[currentQueueIndex];

            if (valueAtCurrentPos <= maximumValueInSequence &&
                this.isNumberPrime(valueAtCurrentPos, smallestPrimeFactors) &&
                !teleportationPrimesUsed[valueAtCurrentPos]) {

                teleportationPrimesUsed[valueAtCurrentPos] = true;

                if (primeFactorToIndicesMap.has(valueAtCurrentPos)) {
                    const jumpTargets = primeFactorToIndicesMap.get(valueAtCurrentPos);
                    let targetIterator = 0;
                    while(targetIterator < jumpTargets.length){
                        const nextJumpTarget = jumpTargets[targetIterator];
                        if (distanceToPosition[nextJumpTarget] === -1) {
                            distanceToPosition[nextJumpTarget] = distanceToPosition[currentQueueIndex] + 1;
                            bfsTraversalQueue.push(nextJumpTarget);
                        }
                        targetIterator++;
                    }
                }
            }
        }

        return -1;
    }
